import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { ArrowLeft, Plus, Tag } from 'lucide-react';
import FormularioOferta from './FormularioOferta';
import ListaOfertas from './ListaOfertas';

const GestionOfertas = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const currentUserId = localStorage.getItem('user-id');
  const [mostrarForm, setMostrarForm] = useState(false);
  const [local, setLocal] = useState(null);

  // 1. CARGA DE OFERTAS
  const [ofertas, setOfertas] = useState(() => {
    const guardadas = localStorage.getItem(`ofertas-local-${id}`);
    return guardadas ? JSON.parse(guardadas) : [];
  });

  // 2. VERIFICACIÓN DE SEGURIDAD
  useEffect(() => {
    const localesGuardados = JSON.parse(localStorage.getItem('mis-locales') || "[]");
    const localEncontrado = localesGuardados.find(l => l.id.toString() === id.toString());
    
    // Seguridad: Si el local no le pertenece al usuario logueado, lo sacamos
    if (!localEncontrado || localEncontrado.duenoId !== currentUserId) {
      alert("No tienes permiso para gestionar este local.");
      navigate('/dashboard');
    } else {
      setLocal(localEncontrado);
    }
  }, [id, currentUserId, navigate]);

  useEffect(() => {
    localStorage.setItem(`ofertas-local-${id}`, JSON.stringify(ofertas));
  }, [ofertas, id]);

  const agregarOferta = (nuevaOferta) => {
    const ofertaCompleta = { 
      id: `off-${Date.now()}`, 
      ...nuevaOferta,
      localId: id,
      duenoId: currentUserId,
      fechaPublicacion: new Date().toISOString()
    };
    setOfertas([ofertaCompleta, ...ofertas]);
    setMostrarForm(false);
  };

  if (!local) return <div style={{ padding: '50px', textAlign: 'center' }}>Verificando permisos...</div>;

  return (
    <div style={containerStyle}>
      <header style={headerStyle}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '20px' }}>
          <button onClick={() => navigate('/dashboard')} style={btnVolver}>
            <ArrowLeft size={22} />
          </button>
          <div>
            <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
              <h1 style={{ margin: 0, fontSize: '1.8rem', color: '#1e293b' }}>{local.nombre}</h1>
              <span style={badgeStyle}>{local.ciudad}</span>
            </div>
            <p style={{ color: '#64748b', margin: '4px 0 0 0' }}>Panel de Control de Inventario</p>
          </div>
        </div>
        
        <button onClick={() => setMostrarForm(true)} style={btnNuevaOferta}>
          <Plus size={20} /> Crear Nueva Oferta
        </button>
      </header>

      <div style={statsRow}>
        <div style={statCard}>
          <Tag color="#e67e22" size={20} />
          <span><strong>{ofertas.length}</strong> Ofertas activas</span>
        </div>
      </div>

      <div style={contentLayout}>
        {mostrarForm ? (
          <FormularioOferta onSave={agregarOferta} onCancel={() => setMostrarForm(false)} />
        ) : (
          <ListaOfertas ofertas={ofertas} onDelete={(oid) => setOfertas(ofertas.filter(o => o.id !== oid))} />
        )}
      </div>
    </div>
  );
};

const containerStyle = { padding: '40px 8%', background: '#f8fafc', minHeight: '90vh' };
const headerStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px' };
const btnVolver = { background: 'white', border: '1px solid #e2e8f0', padding: '12px', borderRadius: '14px', cursor: 'pointer', display: 'flex', transition: '0.2s' };
const btnNuevaOferta = { background: '#1e293b', color: 'white', border: 'none', padding: '14px 25px', borderRadius: '14px', fontWeight: 'bold', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '10px' };
const badgeStyle = { background: '#f1f5f9', color: '#64748b', padding: '4px 12px', borderRadius: '8px', fontSize: '0.75rem', fontWeight: 'bold' };
const statsRow = { marginBottom: '30px' };
const statCard = { background: 'white', display: 'inline-flex', alignItems: 'center', gap: '10px', padding: '12px 20px', borderRadius: '12px', border: '1px solid #e2e8f0', color: '#475569' };
const contentLayout = { maxWidth: '1100px', margin: '0 auto' };

export default GestionOfertas;
